def calc(expr: str) -> float:
    pos = 0
    n = len(expr)

    def peek():
        nonlocal pos
        while pos < n and expr[pos].isspace():
            pos += 1
        return expr[pos] if pos < n else None

    def consume():
        nonlocal pos
        while pos < n and expr[pos].isspace():
            pos += 1
        if pos < n:
            ch = expr[pos]
            pos += 1
            return ch
        return None

    def parse_number():
        nonlocal pos
        start = pos
        while pos < n and expr[pos].isdigit():
            pos += 1
        return float(expr[start:pos])

    def parse_factor():
        ch = peek()
        if ch == '(':
            consume()
            val = parse_expr()
            consume()  # consumes ')'
            return val
        elif ch and ch.isdigit():
            return parse_number()
        else:
            raise ValueError(f"Unexpected character: {ch}")

    def parse_term():
        left = parse_factor()
        while True:
            ch = peek()
            if ch in ('*', '/'):
                consume()
                right = parse_factor()
                if ch == '*':
                    left *= right
                else:
                    left /= right
            else:
                break
        return left

    def parse_expr():
        left = parse_term()
        while True:
            ch = peek()
            if ch in ('+', '-'):
                consume()
                right = parse_term()
                if ch == '+':
                    left += right
                else:
                    left -= right
            else:
                break
        return left

    return parse_expr()
